        int maxDuration = 0;
        int resultId = -1;
        int previousTime = 0;

        for (int[] log : logs) {
            int id = log[0];
            int leaveTime = log[1];
            int duration = leaveTime - previousTime;

            if (duration > maxDuration) {
                maxDuration = duration;
                resultId = id;
            } else if (duration == maxDuration) {
                if (id < resultId) {
